import{c as i,Q as a,j as s,m as t}from"./chunks/framework.CdiUUa3G.js";const m=JSON.parse('{"title":"ADR-020 — Canonical mission JSON schema","description":"","frontmatter":{},"headers":[],"relativePath":"adr/ADR-020.md","filePath":"adr/ADR-020.md"}'),o={name:"adr/ADR-020.md"};function n(d,e,r,l,c,h){return a(),s("div",null,[...e[0]||(e[0]=[t('<h1 id="adr-020-—-canonical-mission-json-schema" tabindex="-1">ADR-020 — Canonical mission JSON schema <a class="header-anchor" href="#adr-020-—-canonical-mission-json-schema" aria-label="Permalink to &quot;ADR-020 — Canonical mission JSON schema&quot;">​</a></h1><blockquote><p>Status · Accepted Date · 2026-04-28 Closes · RFC-002 (mission JSON schema) TA anchor · §contracts/mission-record · §contracts/mission-index-entry</p></blockquote><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>RFC-002 raised three open questions about the mission JSON schema:</p><ol><li>Should the <code>events</code> array be optional or required-but-empty for missions without CAPCOM data?</li><li>Should <code>warning</code> events carry a <code>threshold</code> field, or is anomaly detection purely in code?</li><li>Is <code>data_quality</code> an enum (<code>good</code>, <code>partial</code>, <code>reconstructed</code>) or free text?</li></ol><p>Plus the canonical field names (renaming prototype-era <code>dep</code>, <code>arr</code>, <code>tof</code>, <code>dv</code>, <code>j2000</code> to readable form). Original closure was scheduled for the Slice 4 gate when the schema would be exercised by three mission types in the fly screen. We are closing it at Slice 2 entry instead — before any mission JSON is written — to avoid churning 28 files if the schema changes downstream.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><h3 id="file-layout-three-records-per-mission" tabindex="-1">File layout (three records per mission) <a class="header-anchor" href="#file-layout-three-records-per-mission" aria-label="Permalink to &quot;File layout (three records per mission)&quot;">​</a></h3><ul><li><code>data/missions/index.json</code> — single file, array of lightweight manifest entries</li><li><code>data/missions/[dest]/[id].json</code> — full base record per mission, language-neutral</li><li><code>data/i18n/[locale]/missions/[dest]/[id].json</code> — editorial overlay per mission per locale</li></ul><h3 id="locked-field-names-renames-from-prototype" tabindex="-1">Locked field names (renames from prototype) <a class="header-anchor" href="#locked-field-names-renames-from-prototype" aria-label="Permalink to &quot;Locked field names (renames from prototype)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Prototype</th><th>Canonical</th><th>Reason</th></tr></thead><tbody><tr><td><code>dep</code></td><td><code>departure_date</code></td><td>Unambiguous</td></tr><tr><td><code>arr</code></td><td><code>arrival_date</code></td><td>Unambiguous</td></tr><tr><td><code>tof</code></td><td><code>transit_days</code></td><td>Self-documenting unit</td></tr><tr><td><code>dv</code></td><td><code>delta_v</code></td><td>Consistent with physics notation</td></tr><tr><td><code>j2000</code></td><td>(removed)</td><td>Computable from dates</td></tr></tbody></table><p>All other prototype field names retained: <code>id</code>, <code>agency</code>, <code>agency_full</code>, <code>dest</code>, <code>status</code>, <code>year</code>, <code>sector</code>, <code>color</code>, <code>first</code>, <code>description</code>, <code>data_quality</code>, <code>credit</code>, <code>links</code>, <code>name</code>, <code>type</code>, <code>vehicle</code>, <code>payload</code>.</p><h3 id="strictness-additionalproperties-false-everywhere" tabindex="-1">Strictness: <code>additionalProperties: false</code> everywhere <a class="header-anchor" href="#strictness-additionalproperties-false-everywhere" aria-label="Permalink to &quot;Strictness: `additionalProperties: false` everywhere&quot;">​</a></h3><p>Unknown fields fail validation. Catches typos and stale fields at PR time. Adding a new field is intentional, not accidental.</p><h3 id="answers-to-rfc-002-open-questions" tabindex="-1">Answers to RFC-002 open questions <a class="header-anchor" href="#answers-to-rfc-002-open-questions" aria-label="Permalink to &quot;Answers to RFC-002 open questions&quot;">​</a></h3><ol><li><strong><code>events</code> is required</strong> in mission overlays. Every Slice 4 mission has at least LAUNCH and arrival/landing events. Earth-orbit objects and Moon sites have separate overlay schemas where <code>events</code> does not apply.</li><li><strong>No <code>threshold</code> field on warning events in v1.</strong> Anomaly thresholds live in code. Adding <code>threshold</code> is a v2 candidate when CAPCOM gains user-configurable alerts.</li><li><strong><code>data_quality</code> is an enum</strong>: <code>good</code> | <code>partial</code> | <code>reconstructed</code>. Free text rejected because it makes UI badging ambiguous; the enum drives a small visual contract (no badge for <code>good</code>, amber badge for the other two).</li></ol><h3 id="events-shape-in-mission-overlays" tabindex="-1">Events shape (in mission overlays) <a class="header-anchor" href="#events-shape-in-mission-overlays" aria-label="Permalink to &quot;Events shape (in mission overlays)&quot;">​</a></h3><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{ </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;met&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#B31D28;--shiki-light-font-style:italic;--shiki-dark:#FDAEB7;--shiki-dark-font-style:italic;">&lt;number&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;label&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;STRING&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;note&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;STRING&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;type&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;nominal&quot;</span><span style="--shiki-light:#B31D28;--shiki-light-font-style:italic;--shiki-dark:#FDAEB7;--shiki-dark-font-style:italic;"> |</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;info&quot;</span><span style="--shiki-light:#B31D28;--shiki-light-font-style:italic;--shiki-dark:#FDAEB7;--shiki-dark-font-style:italic;"> |</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;warning&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }</span></span></code></pre></div><p><code>met</code> is <strong>days from departure</strong> (not seconds — &quot;T+22377600s&quot; is unreadable, &quot;T+259d&quot; is human).</p><h2 id="rationale" tabindex="-1">Rationale <a class="header-anchor" href="#rationale" aria-label="Permalink to &quot;Rationale&quot;">​</a></h2><p>Closing now instead of at Slice 4 gate avoids rewriting 28 mission files if the schema needs to change after the fly screen exercises it. The risk that Slice 4 surfaces new requirements is low — RFC-002&#39;s proposed approach was already validated against the prototype&#39;s embedded data shape, and Issue #2&#39;s spec enumerates the field set exhaustively.</p><p>Strict schema (<code>additionalProperties: false</code>) is locked because the cost is one line per schema and the win is catching typos like <code>agency_fl</code> instead of <code>agency_full</code> at PR time.</p><h2 id="alternatives-considered" tabindex="-1">Alternatives considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives considered&quot;">​</a></h2><ul><li><strong>Defer to Slice 4 gate</strong> — original RFC-002 plan. Rejected: real risk of churning 28 mission files if any field changes; schema design is mature enough to lock now.</li><li><strong>Open schema (<code>additionalProperties: true</code>)</strong> — allows experimentation. Rejected per ADR-019 spirit (validation should fail loudly at PR time).</li><li><strong><code>events</code> optional</strong> — simpler for mission types without timeline. Rejected: every Slice 4 mission has launch/arrival events; missions without them shouldn&#39;t appear in the mission library at all.</li></ul><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><p>Positive: schema locked before any mission JSON is written → zero rework risk; strict validation catches typos; events shape unambiguous for CAPCOM mode. Negative: Slice 4 may surface a need for an additional field; adding requires updating the schema + 28 files. Mitigation: schema is informed by both the prototype (complete) and Issue #2&#39;s exhaustive field list.</p><h2 id="implementation-notes" tabindex="-1">Implementation notes <a class="header-anchor" href="#implementation-notes" aria-label="Permalink to &quot;Implementation notes&quot;">​</a></h2><p>Schema files live in <code>data/schemas/</code>:</p><ul><li><code>mission.schema.json</code> — base mission record</li><li><code>mission-index.schema.json</code> — <code>index.json</code> entry</li><li><code>mission-overlay.schema.json</code> — locale overlay</li></ul><p>Validator: <code>scripts/validate-data.ts</code> runs ajv against all base + overlay files. CI step blocks PR on schema failure (per ADR-019).</p>',30)])])}const u=i(o,[["render",n]]);export{m as __pageData,u as default};
